  bfg:       { id:'bfg',       name:'БФГ-9000',     type:ItemType.WEAPON,    desc:'Тяжёлый опытный ствол НИИ. Урон 270 по большой площади. Энергоячейки исчезают вместе с комнатой', spawnRooms:[], spawnW:0, value:180000 },
