  sledgehammer:{ id:'sledgehammer', name:'Кувалда', type:ItemType.WEAPON, desc:'Медленная кувалда. Урон 52. Большой замах, большой стоп. Прочность 85', spawnRooms:[RoomType.PRODUCTION], spawnW:1, value:260 },
  fire_hook:{ id:'fire_hook', name:'Пожарный багор', type:ItemType.WEAPON, desc:'Самый длинный ближний бой. Урон 18. Держит тварь на вытянутой руке. Прочность 80', spawnRooms:[RoomType.STORAGE,RoomType.CORRIDOR], spawnW:1, value:120 },
