  tt_pistol:{ id:'tt_pistol', name:'ТТ', type:ItemType.WEAPON, desc:'Пистолет ТТ. Урон 34. Мощнее ПМ, патроны 7.62 ТТ', spawnRooms:[RoomType.HQ,RoomType.STORAGE], spawnW:1, value:650 },
  nagant:{ id:'nagant', name:'Револьвер Наган', type:ItemType.WEAPON, desc:'Старый револьвер. Урон 48. Очень медленный точный выстрел', spawnRooms:[RoomType.OFFICE,RoomType.STORAGE], spawnW:1, value:720 },
  homemade_pistol:{ id:'homemade_pistol', name:'Кустарный пистолет', type:ItemType.WEAPON, desc:'Короткоствол из мастерской и чужого чертежа. Урон 27. Сильный разброс; живёт на дефицитной 9мм и гильзоплавке.', spawnRooms:[RoomType.PRODUCTION,RoomType.STORAGE], spawnW:0.55, value:350, tags:['weapon','sidearm','homemade','contraband','craft_pistol','ammo_9mm'] },
