  chest_failsafe_charge:{ id:'chest_failsafe_charge', name:'Фугасный нагрудный заряд', type:ItemType.WEAPON, desc:'Опломбированный аварийный фугас. Урон 175 по площади. Один рывок, один взрыв, один рапорт: украсть, продать или оставить на безвыходный коридор.', spawnRooms:[], spawnW:0, value:1650, tags:['weapon','liquidator','explosive','grenade','failsafe','single_use','contraband','panic_clear','story_rare'], stack:1 },
