  pushkin_shotgun:{ id:'pushkin_shotgun', name:'Ружьё «Пушкин»', type:ItemType.WEAPON, desc:'Редкая тактическая платформа под дробь. Урон 14x6. Точнее РБ-91, медленнее автоматики: купи у ряда 88 или вскрой ящик.', spawnRooms:[RoomType.HQ,RoomType.SMOKING], spawnW:0.018, value:3200, tags:['weapon','liquidator','shotgun','ammo_shells','tactical','black_market','rare','shell_platform','corridor_stop'] },
  rpl23_lmg:{ id:'rpl23_lmg', name:'РПЛ-23 Лёшкинского', type:ItemType.WEAPON, desc:'Отрядный ручной пулемёт. Урон 14. Лента тает быстро, зато проход спорит меньше.', spawnRooms:[RoomType.HQ], spawnW:0.025, value:8500, tags:['weapon','liquidator','lmg','ammo_belt','ammo_burn','engineer_stash','deep_route'] },
  p41_heavy_mg:{ id:'p41_heavy_mg', name:'6П41 пулемёт', type:ItemType.WEAPON, desc:'Станковый пулемёт инженерной смены. Урон 18. Лента исчезает быстрее, чем ревизия моргает; на маршруте это кража, а не находка.', spawnRooms:[], spawnW:0, value:15000, tags:['weapon','liquidator','heavy_mg','ammo_belt','ammo_burn','mounted','stationary','production_belt','theft'] },
  roks47_flamethrower:{ id:'roks47_flamethrower', name:'РОКС-47', type:ItemType.WEAPON, desc:'Ранцевый огнемёт ликвидатора. Урон 7x2 за плевок. Жжёт шире обычного огнемёта и просит напалм.', spawnRooms:[RoomType.HQ,RoomType.PRODUCTION], spawnW:0.045, value:9000, tags:['weapon','liquidator','flame','cleanup','slime_counterplay','napalm','issue_stash'] },
  agnia_a130:{ id:'agnia_a130', name:'А-130 «Агния»', type:ItemType.WEAPON, desc:'Санитарный коридорный огнемёт. Урон 4x2. Слабее в бою, ровнее выжигает налёт обычным топливом.', spawnRooms:[RoomType.PRODUCTION,RoomType.HQ], spawnW:0.08, value:5500, tags:['weapon','liquidator','flame','cleanup','sanitary','slime_counterplay','technical_cleanup','fuel_clear'] },
  o15_multijet_flamer:{ id:'o15_multijet_flamer', name:'6О15-УТТХ', type:ItemType.WEAPON, desc:'Инженерная прожигалка с тремя соплами. Урон 6x3. Медленнее РОКСа, но режет узкий проход напалмом.', spawnRooms:[RoomType.HQ,RoomType.PRODUCTION], spawnW:0.012, value:15000, tags:['weapon','liquidator','engineer','flame','breach','napalm','deep_engineer_stash','slime_counterplay'] },
  shmk_disposable:{ id:'shmk_disposable', name:'ШМК', type:ItemType.WEAPON, desc:'Одноразовый огневой пакет. Урон 11x8. Выстрелил - и коробка ушла; рядом с документами лучше не проверять.', spawnRooms:[RoomType.HQ,RoomType.STORAGE], spawnW:0.08, value:520, tags:['weapon','liquidator','flame','cleanup','single_use','panic_clear','fuel','fuel_clear','collateral','rare_crate'] },
  foam_grenade_6p10:{ id:'foam_grenade_6p10', name:'Пенобетонная граната 6П10', type:ItemType.WEAPON, desc:'Контрольная граната ликвидатора. Урон 18 по широкой площади. Носится пачкой: бросить сейчас или сберечь для узкого коридора.', spawnRooms:[RoomType.HQ,RoomType.PRODUCTION], spawnW:0.09, value:260, tags:['weapon','liquidator','foam','grenade','control','self_ammo','issue_stash','panic_control'], stack:6 },
  brt2_foam_projector:{ id:'brt2_foam_projector', name:'БРТ-2 бетономёт', type:ItemType.WEAPON, desc:'Инженерный пенобетонный проектор. Урон 12 по малому пятну. Заряжается 6П10: украсть из серого ящика, прижать проход или сбить темп самосбора.', spawnRooms:[], spawnW:0, value:3100, tags:['weapon','liquidator','foam','projector','engineer','control','immobilizer','foam_grenade_ammo','rare_engineer_crate'] },
