  breach_charge:{ id:'breach_charge', name:'Пробивной заряд', type:ItemType.WEAPON, desc:'Инженерная шашка для двери, биомассы и плохой стены. Урон 130 по малой площади. Шум слышит весь этаж.', spawnRooms:[RoomType.HQ,RoomType.PRODUCTION], spawnW:0.045, value:740, tags:['weapon','liquidator','breach','grenade','engineer','self_ammo','collateral','door_work','biomass'], stack:2 },
  concrete_breaker_grenade:{ id:'concrete_breaker_grenade', name:'Бетонобойная граната', type:ItemType.WEAPON, desc:'Инженерная бетонка для плотной цели и плохого шва. Урон 105 по средней площади. Бросить сейчас, украсть из ящика или сберечь до тупика.', spawnRooms:[RoomType.HQ,RoomType.PRODUCTION], spawnW:0.025, value:620, tags:['weapon','liquidator','grenade','breach','engineer','concrete','rare_stash','single_use'], stack:4 },
  pistol_grenade_launcher:{ id:'pistol_grenade_launcher', name:'Пистолет-гранатомёт', type:ItemType.WEAPON, desc:'Ополченская редкость под обычную гранату. Урон 70 по площади. Дальше броска, опаснее репутации.', spawnRooms:[RoomType.STORAGE,RoomType.SMOKING,RoomType.HQ], spawnW:0.035, value:5200, tags:['weapon','militia','grenade','contraband','single_shot','self_risk','rare_stash'] },
  party_might_launcher:{ id:'party_might_launcher', name:'Подствольник «Мощь партии»', type:ItemType.WEAPON, desc:'Съёмный ликвидаторский гранатомёт без системы креплений. Урон 110 по площади. Носится как отдельная беда.', spawnRooms:[RoomType.HQ], spawnW:0.018, value:8000, tags:['weapon','liquidator','grenade','breach','rare'] },
  g41_grenade_launcher:{ id:'g41_grenade_launcher', name:'5Г41 станковый гранатомёт', type:ItemType.WEAPON, desc:'Пломбированный станковый гранатомёт смены 14. Урон 125 по площади. Станок стоит на маршруте; украсть его можно, но каждая граната пишет ревизию.', spawnRooms:[], spawnW:0, value:12000, tags:['weapon','liquidator','grenade','mounted','stationary','production_belt','theft'] },
