  psi_storm:    { id:'psi_storm',     name:'Сгусток: Пси буря',        type:ItemType.WEAPON, desc:'Пакетированный многоточечный импульс: 19 ПСИ, бьёт врагов в поле зрения. Дорогой ответ на толпу.',                       spawnRooms:[RoomType.MEDICAL],                                spawnW:0.35, value:36000 },
  psi_brainburn:{ id:'psi_brainburn', name:'Сгусток: Выжиг мозга',     type:ItemType.WEAPON, desc:'Запрещённый импульс НИИ: 22 ПСИ. Убивает цель не выше вашего уровня.',                     spawnRooms:[RoomType.MEDICAL],                                spawnW:0.25, value:52000 },
  psi_madness:  { id:'psi_madness',   name:'Сгусток: Безумие',         type:ItemType.WEAPON, desc:'Сбойный поведенческий импульс: 10 ПСИ, цель 15с +1с/ИНТ атакует ближайших. Потом объяснения не принимают.',                                 spawnRooms:[RoomType.OFFICE,RoomType.COMMON],                 spawnW:0.65, value:18000 },
  psi_control:  { id:'psi_control',   name:'Сгусток: Контроль',        type:ItemType.WEAPON, desc:'Принудительный ПСИ-захват: 20 ПСИ, цель 15с +1с/ИНТ считает вас союзником. Используйте это время на отход.',                              spawnRooms:[RoomType.MEDICAL],                                spawnW:0.25, value:64000 },
  psi_shield:   { id:'psi_shield',    name:'Сгусток: ПСИ-щит',         type:ItemType.WEAPON, desc:'Защитный ПСИ-контур: 12 ПСИ, 15с +1с/ИНТ не дает HP просесть. 10% входящего урона уходит из запаса ПСИ.', spawnRooms:[RoomType.MEDICAL,RoomType.HQ], spawnW:0.3, value:30000 },
  psi_possession:{ id:'psi_possession', name:'Сгусток: Вселение',       type:ItemType.WEAPON, desc:'Запрещённый перенос НИИ: 26 ПСИ, 15с +1с/ИНТ ведёт чужое тело, если ваш интеллект выше цели. Ваше тело остаётся на месте.', spawnRooms:[RoomType.MEDICAL], spawnW:0.12, value:76000 },
  psi_phase:    { id:'psi_phase',     name:'Сгусток: Фазовый сдвиг',   type:ItemType.WEAPON, desc:'Проход через стену: 17 ПСИ, 15с +1с/ИНТ. Не останавливайтесь внутри препятствия.',                                 spawnRooms:[RoomType.STORAGE],                                spawnW:0.2, value:70000 },
  psi_mark:     { id:'psi_mark',      name:'Сгусток: Метка',           type:ItemType.WEAPON, desc:'Метка возврата: 4 ПСИ. Ставит точку, куда потом тянет сгусток Возврат.',                              spawnRooms:[RoomType.MEDICAL,RoomType.OFFICE],                spawnW:0.8, value:10000 },
  psi_recall:   { id:'psi_recall',    name:'Сгусток: Возврат',         type:ItemType.WEAPON, desc:'Возврат к ПСИ-метке: 8 ПСИ. Работает лучше, если метка стоит у укрытия или лифта.',                                             spawnRooms:[RoomType.MEDICAL,RoomType.OFFICE],                spawnW:0.65, value:18000 },
  psi_beam:     { id:'psi_beam',      name:'Сгусток: ПСИ-луч',        type:ItemType.WEAPON, desc:'Сфокусированный ПСИ-луч: 14 ПСИ за импульс, 28 урона по линии. Держать как режущий инструмент.', spawnRooms:[RoomType.MEDICAL], spawnW:0.18, value:45000 },
  psi_concrete_splinter:{ id:'psi_concrete_splinter', name:'Сгусток: Бетонный осколок', type:ItemType.WEAPON, desc:'ПСИ-осколок: 6 ПСИ, 23 урона. Дешёвый направленный удар для узкого прохода.', spawnRooms:[RoomType.MEDICAL,RoomType.PRODUCTION], spawnW:0.75, value:14000 },
  psi_shadow_lance:{ id:'psi_shadow_lance', name:'Сгусток: Теневая пика', type:ItemType.WEAPON, desc:'Быстрый теневой прокол: 12 ПСИ, 44 урона. В журнале проходит как направленный риск.', spawnRooms:[RoomType.MEDICAL,RoomType.OFFICE], spawnW:0.45, value:24000 },
  psi_order_seal:{ id:'psi_order_seal', name:'Сгусток: Печать порядка', type:ItemType.WEAPON, desc:'Плотный импульс печати: 12 ПСИ, 27 урона по малой площади. Не ставить рядом с бланками.', spawnRooms:[RoomType.OFFICE,RoomType.HQ], spawnW:0.4, value:24000 },
  psi_void_needle:{ id:'psi_void_needle', name:'Сгусток: Пустотная игла', type:ItemType.WEAPON, desc:'Точный лабораторный импульс: 23 ПСИ, 96 урона. Берегите для сильной одиночной цели.', spawnRooms:[RoomType.MEDICAL], spawnW:0.15, value:70000 },
  psi_meat_hook:{ id:'psi_meat_hook', name:'Сгусток: Мясной крюк', type:ItemType.WEAPON, desc:'Тяжёлый органический снаряд: 13 ПСИ, 50 урона. Тару после переноски мыть йодом.', spawnRooms:[RoomType.MEDICAL,RoomType.STORAGE], spawnW:0.45, value:26000 },
  psi_siren_pulse:{ id:'psi_siren_pulse', name:'Сгусток: Сиренный импульс', type:ItemType.WEAPON, desc:'ПСИ-импульс с малым разрывом: 13 ПСИ, 22 урона. Не стойте рядом с целью.', spawnRooms:[RoomType.HQ,RoomType.OFFICE], spawnW:0.35, value:32000 },

  // ── Документы, экономика, компоненты и лор AG07 ──
  spore_print:{ id:'spore_print', name:'Споровый отпечаток', type:ItemType.MISC, desc:'Темный отпечаток на бумаге. С него начинают грибную смену.', spawnRooms:[RoomType.STORAGE,RoomType.PRODUCTION], spawnW:1, value:12 },
  substrate_sack:{ id:'substrate_sack', name:'Мешок субстрата', type:ItemType.MISC, desc:'Влажная труха для стеллажей. Пахнет коллектором и обедом.', spawnRooms:[RoomType.STORAGE,RoomType.PRODUCTION,RoomType.BATHROOM], spawnW:1, value:10 },
  water_coupon:{ id:'water_coupon', name:'Талон на воду', type:ItemType.MISC, desc:'Бумага на право одной бутылки. Используйте честно, украдите как улику или пустите в подделку.', spawnRooms:[RoomType.OFFICE,RoomType.COMMON,RoomType.KITCHEN], spawnW:1, value:2 },
  concentrate_coupon:{ id:'concentrate_coupon', name:'Талон на концентрат', type:ItemType.MISC, desc:'Пищевой талон с жирной печатью. Обычно гасится на беляк; черняк, красняк и спецпай требуют чужой строки.', spawnRooms:[RoomType.OFFICE,RoomType.COMMON,RoomType.STORAGE], spawnW:1, value:3 },
  cult_supply_list:{ id:'cult_supply_list', name:'Кухонный список ячейки', type:ItemType.MISC, desc:'Хлеб, ключи, фамилии и стрелки к чужим кастрюлям. Доказательство пахнет кипятком.', spawnRooms:[RoomType.KITCHEN,RoomType.STORAGE,RoomType.OFFICE], spawnW:1, value:38 },
