  liquidator_token:{ id:'liquidator_token', name:'Жетон ликвидатора', type:ItemType.MISC, desc:'Служебный жетон с номером отряда. На посту его узнают быстрее фамилии.', spawnRooms:[RoomType.HQ,RoomType.STORAGE], spawnW:1, value:80 },
  portable_siren_key:{ id:'portable_siren_key', name:'Ключ переносной сирены', type:ItemType.MISC, desc:'Служебный ключ к переносной сирене. Сейф его хранит как ремонт, взятку или улику перед следующей тревогой.', spawnRooms:[RoomType.HQ,RoomType.OFFICE], spawnW:0.35, value:85, tags:['repair','siren','warning','liquidator','electronics','service'], stack:1 },
  body_bag_roll:{ id:'body_bag_roll', name:'Рулон мешков для тел', type:ItemType.MISC, desc:'Плотный санитарный рулон после отбоя. Им закрывают тело или отчёт: сдать ликвидатору, спрятать след или продать медпосту.', spawnRooms:[RoomType.HQ,RoomType.MEDICAL], spawnW:0.45, value:58, tags:['medical','cleanup','corpse','liquidator','evidence','samosbor','trade'], stack:4 },
  corpse_number_tag:{ id:'corpse_number_tag', name:'Номерок трупа', type:ItemType.MISC, desc:'Жестяная бирка после зачистки. Морг платит за отчёт, рынок - за чужую пустую строку; можно сдать, продать или спрятать.', spawnRooms:[RoomType.MEDICAL,RoomType.HQ,RoomType.STORAGE], spawnW:0.35, value:38, tags:['document','evidence','identity','corpse','morgue','liquidator','cleanup'], stack:24 },
  fake_pass:{ id:'fake_pass', name:'Фальшивый пропуск', type:ItemType.MISC, desc:'Почти правильный цвет и чужая печать. На посту рискнут спросить фамилию.', spawnRooms:[RoomType.OFFICE,RoomType.SMOKING], spawnW:1, value:45 },
  zhek_seal:{ id:'zhek_seal', name:'Печать ЖЭК', type:ItemType.MISC, desc:'Резиновая печать для актов, жалоб и мокрых справок.', spawnRooms:[RoomType.OFFICE,RoomType.COMMON], spawnW:1, value:120 },
  hermo_gasket:{ id:'hermo_gasket', name:'Гермопрокладка', type:ItemType.MISC, desc:'Сухая резиновая прокладка для гермодвери и лифтового тамбура. Потратьте на дверной щиток, отдайте ремонтнику или берегите до сирены.', spawnRooms:[RoomType.STORAGE,RoomType.PRODUCTION], spawnW:1, value:60, tags:['repair','seal','hermodoor','lift','samosbor','tool'] },
  fuse:{ id:'fuse', name:'Предохранитель', type:ItemType.MISC, desc:'Маленькая деталь между светом, терминалом и пожаром. Электрик берёт первым, спорит потом.', spawnRooms:[RoomType.PRODUCTION,RoomType.STORAGE], spawnW:1, value:20 },
  gasmask_filter:{ id:'gasmask_filter', name:'Фильтр противогаза', type:ItemType.MISC, desc:'Сухой сменный фильтр. В смоге уходит в расход, от спор и борщевика бережёт горло. Сберечь для маршрута, сдать или продать.', spawnRooms:[RoomType.MEDICAL,RoomType.STORAGE,RoomType.HQ], spawnW:0.8, value:70, stack:6 },
  ozk_patch:{ id:'ozk_patch', name:'Заплата ОЗК', type:ItemType.MISC, desc:'Прорезиненная заплата с клеевой кромкой. Ликвидатор тратит её на дырявый ОЗК; вор продаёт как дефицит.', spawnRooms:[RoomType.MEDICAL,RoomType.HQ,RoomType.STORAGE], spawnW:0.65, value:46, tags:['repair','repair_input','liquidator','ppe'], stack:8 },
