  radio:{ id:'radio', name:'Рация', type:ItemType.TOOL, desc:'Рабочая рация для докладов и слухов. Полезна там, где ликвидаторы принимают сигнал.', spawnRooms:[RoomType.HQ,RoomType.OFFICE,RoomType.STORAGE], spawnW:1, value:180, durability:120 },
  radio_headset_liquidator:{ id:'radio_headset_liquidator', name:'Гарнитура ликвидатора', type:ItemType.TOOL, desc:'Уставная гарнитура с костяным треском эфира. В инструменте расширяет слышимость докладов и чужих криков; продать проще, чем объяснить номер смены.', spawnRooms:[RoomType.HQ,RoomType.OFFICE,RoomType.STORAGE], spawnW:0.18, value:260, durability:90, tags:['liquidator','radio','headset','hearing_boost','electronics','trade'] },
  field_radio_battery:{ id:'field_radio_battery', name:'Батарея рации', type:ItemType.MISC, desc:'Плоский блок питания к полевой рации. Оставьте для связи, продайте электрику или обменяйте как дефицитную электронику.', spawnRooms:[RoomType.STORAGE,RoomType.OFFICE], spawnW:0.75, value:38, tags:['electronics','battery','radio','trade'], stack:6 },
