  stolen_filter_pack:{ id:'stolen_filter_pack', name:'Краденая пачка фильтров', type:ItemType.MISC, desc:'Сухие фильтры без квитанции. E: вскрыть пачку на два фильтра; дышать помогают, но склад помнит номера.', spawnRooms:[RoomType.STORAGE,RoomType.HQ,RoomType.SMOKING], spawnW:0.35, value:120, tags:[...ITEM_TAGS.stolen_filter_pack], stack:3, use:unpackStolenFilterPack },
  black_market_shells:{ id:'black_market_shells', name:'Чёрнорыночная дробь', type:ItemType.AMMO, desc:'Дробовые патроны с перебитым учётом. E: переложить в обычный подсумок, потеряв часть доказательств.', spawnRooms:[], spawnW:0, value:42, tags:[...ITEM_TAGS.black_market_shells], stack:12, use:unpackBlackMarketShells },
  contraband_shocker_parts:{ id:'contraband_shocker_parts', name:'Детали шокера', type:ItemType.MISC, desc:'Катушка, рукоять и чужой предохранитель. Продайте Жоке, спрячьте от поста или несите в техническую кладовую на подпольную сборку.', spawnRooms:[RoomType.PRODUCTION,RoomType.OFFICE,RoomType.SMOKING], spawnW:0.25, value:150, tags:[...ITEM_TAGS.contraband_shocker_parts], stack:2 },
  junior_tech_case:{ id:'junior_tech_case', name:'Корпус «Юный техник»', type:ItemType.MISC, desc:'Пластиковый корпус набора радиолюбителя. В него помещается прибор, долг и маленькое жужжание.', spawnRooms:[RoomType.LIVING,RoomType.STORAGE,RoomType.OFFICE], spawnW:0.7, value:24, tags:[...ITEM_TAGS.junior_tech_case], stack:6 },
  sound_emitter:{ id:'sound_emitter', name:'Звукоизлучатель', type:ItemType.MISC, desc:'Пищалка из старого стенда. Не приманка: для неё есть банка. Эту деталь берегут для датчика, продают электрику или сдают в цех.', spawnRooms:[RoomType.OFFICE,RoomType.PRODUCTION,RoomType.STORAGE], spawnW:0.35, value:58, tags:[...ITEM_TAGS.sound_emitter], stack:4 },
  keyboard_unit:{ id:'keyboard_unit', name:'Клавиатура', type:ItemType.MISC, desc:'Блок клавиш от терминала. Половина букв стерта, зато E ещё нажимается.', spawnRooms:[RoomType.OFFICE,RoomType.STORAGE,RoomType.PRODUCTION], spawnW:0.6, value:32, tags:['electronics','terminal','repair'], stack:4 },
